//! Emit the Rust facade client surface (async + blocking) from catalog + binding IR.

use std::collections::{BTreeMap, BTreeSet};
use std::fmt::Write as _;

use crate::doc_render::render_entry_doc_lines;
use crate::error::GenResult;
use crate::ir::{
    Ir, IrBindingArtifact, IrBindingCatalogLink, IrBindingSymbol, IrEntryPoint, IrEntrySection,
    IrSerializeKind, IrSyncKind, IrTypeRef,
};

const CLIENT_HEADER: &str =
    "// @generated by dto-gen — do not edit. Regenerate with --rs-client-out.\n\n";
const BLOCKING_HEADER: &str =
    "// @generated by dto-gen — do not edit. Regenerate with --rs-client-out.\n\n";

/// Public Rust facade files emitted from canonical catalog and binding IR.
pub struct EmittedRustClient {
    /// `crates/solvapay/src/client_generated.rs`.
    pub client_generated_rs: String,
    /// `crates/solvapay/src/blocking_generated.rs`.
    pub blocking_generated_rs: String,
}

/// One catalogued client operation ready for Rust facade emission.
#[derive(Debug, Clone)]
struct MethodRow<'a> {
    entry: &'a IrEntryPoint,
    name: &'a str,
    params: Vec<RustParam>,
    ok_type: String,
}

#[derive(Debug, Clone)]
struct RustParam {
    name: String,
    ty: String,
}

/// Emits async + blocking Rust facade client methods with rustdoc.
///
/// # Errors
///
/// Returns formatting failures as [`crate::error::GenError`].
pub fn emit_client_rs(ir: &Ir) -> GenResult<EmittedRustClient> {
    let rows = method_rows(ir)?;
    Ok(EmittedRustClient {
        client_generated_rs: emit_async_client(&rows),
        blocking_generated_rs: emit_blocking_client(&rows),
    })
}

/// Selects catalogued client operations (`Operation` + `Client` binding).
///
/// Reuses `names.rust`, `availability.rust`, and binding serialize shape — no
/// speculative `IrRustTarget` field (Step 47).
pub(crate) fn client_operations(ir: &Ir) -> Vec<(&IrEntryPoint, &IrBindingSymbol)> {
    let bindings = binding_by_catalog(ir, IrBindingArtifact::Client);
    let mut ops: Vec<_> = ir
        .entry_points
        .values()
        .filter(|entry| entry.section == IrEntrySection::Operation)
        .filter(|entry| {
            entry
                .availability
                .rust
                .iter()
                .any(|mode| matches!(mode, IrSyncKind::Async | IrSyncKind::Sync))
        })
        .filter_map(|entry| {
            bindings
                .get(entry.id.as_str())
                .map(|binding| (entry, *binding))
        })
        .collect();
    ops.sort_by(|left, right| left.0.names.rust.cmp(&right.0.names.rust));
    ops
}

fn method_rows(ir: &Ir) -> GenResult<Vec<MethodRow<'_>>> {
    let mut rows = Vec::new();
    for (entry, binding) in client_operations(ir) {
        rows.push(MethodRow {
            entry,
            name: entry.names.rust.as_str(),
            params: rust_params(entry, binding)?,
            ok_type: rust_ok_type(entry),
        });
    }
    Ok(rows)
}

fn emit_async_client(rows: &[MethodRow<'_>]) -> String {
    let mut output = String::from(CLIENT_HEADER);
    write_imports(&mut output, rows, false);
    output.push_str("#[allow(clippy::missing_docs_in_private_items)]\nimpl Client {\n");
    for row in rows {
        write_rustdoc(&mut output, row, "    ");
        let sig = format_params(&row.params);
        let call_args = format_call_args(&row.params);
        let _ = writeln!(
            output,
            "    pub async fn {}(&self{sig}) -> Result<{}, SdkError> {{\n\
             \x20       self.inner.api.{}({call_args}).await\n\
             \x20   }}\n",
            row.name, row.ok_type, row.name
        );
    }
    while output.ends_with("\n\n") {
        output.pop();
    }
    if !output.ends_with('\n') {
        output.push('\n');
    }
    output.push_str("}\n");
    output
}

fn emit_blocking_client(rows: &[MethodRow<'_>]) -> String {
    let mut output = String::from(BLOCKING_HEADER);
    write_imports(&mut output, rows, true);
    output.push_str("#[allow(clippy::missing_docs_in_private_items)]\nimpl BlockingClient {\n");
    for row in rows {
        write_rustdoc(&mut output, row, "    ");
        let sig = format_params(&row.params);
        let call_args = format_call_args(&row.params);
        let _ = writeln!(
            output,
            "    pub fn {}(&self{sig}) -> Result<{}, SdkError> {{\n\
             \x20       runtime().block_on(self.inner.{}({call_args}))\n\
             \x20   }}\n",
            row.name, row.ok_type, row.name
        );
    }
    while output.ends_with("\n\n") {
        output.pop();
    }
    if !output.ends_with('\n') {
        output.push('\n');
    }
    output.push_str("}\n");
    output
}

fn write_imports(output: &mut String, rows: &[MethodRow<'_>], _blocking: bool) {
    let mut dto_types = BTreeSet::new();
    let mut needs_value = false;
    for row in rows {
        if row.ok_type == "Value" {
            needs_value = true;
        } else if row.ok_type != "()" && !row.ok_type.contains("::") {
            dto_types.insert(row.ok_type.clone());
        }
        for param in &row.params {
            if let Some(inner) = param
                .ty
                .strip_prefix("Option<")
                .and_then(|rest| rest.strip_suffix('>'))
            {
                if inner != "Value" && !inner.starts_with('&') {
                    dto_types.insert(inner.to_owned());
                }
            } else if param.ty != "Value" && !param.ty.starts_with('&') && param.ty != "()" {
                dto_types.insert(param.ty.clone());
            }
        }
    }

    // Child module of `client` / `blocking` (via `#[path = "…_generated.rs"]`).
    if needs_value {
        output.push_str("use serde_json::Value;\n");
    }
    output.push_str("use solvapay_core::SdkError;\n");
    if !dto_types.is_empty() {
        output.push_str("use solvapay_dto::{\n");
        for ty in &dto_types {
            let _ = writeln!(output, "    {ty},");
        }
        output.push_str("};\n");
    }
    if _blocking {
        output.push_str("\nuse super::{runtime, BlockingClient};\n\n");
    } else {
        output.push_str("\nuse super::Client;\n\n");
    }
}

fn write_rustdoc(output: &mut String, row: &MethodRow<'_>, indent: &str) {
    let lines = render_rustdoc(row.entry);
    if lines.is_empty() {
        return;
    }
    for line in lines {
        if line.is_empty() {
            let _ = writeln!(output, "{indent}///");
        } else {
            let _ = writeln!(output, "{indent}/// {line}");
        }
    }
}

/// Maps shared IR doc lines into idiomatic rustdoc (`# Arguments` / `# Returns`).
fn render_rustdoc(entry: &IrEntryPoint) -> Vec<String> {
    let raw = render_entry_doc_lines(entry, |p| p.names.rust.as_str());
    let mut out = Vec::new();
    let mut params = Vec::new();
    let mut returns = None;
    for line in raw {
        if let Some(rest) = line.strip_prefix("@param ") {
            params.push(rest.to_owned());
        } else if let Some(rest) = line.strip_prefix("@returns ") {
            returns = Some(rest.to_owned());
        } else {
            out.push(line);
        }
    }
    if !params.is_empty() {
        if !out.is_empty() {
            out.push(String::new());
        }
        out.push("# Arguments".into());
        out.push(String::new());
        for param in params {
            let (name, doc) = split_param_doc(&param);
            out.push(format!("* `{name}` — {doc}"));
        }
    }
    if let Some(returns) = returns {
        if !out.is_empty() {
            out.push(String::new());
        }
        out.push("# Returns".into());
        out.push(String::new());
        out.push(returns);
    }
    out
}

fn split_param_doc(line: &str) -> (&str, &str) {
    match line.split_once(' ') {
        Some((name, doc)) => (name, doc.trim()),
        None => (line, ""),
    }
}

fn rust_params(entry: &IrEntryPoint, binding: &IrBindingSymbol) -> GenResult<Vec<RustParam>> {
    let kind = serialize_kind(binding)?;
    match kind {
        IrSerializeKind::ClientIgnore => Ok(Vec::new()),
        IrSerializeKind::ClientAwait => {
            let dto = binding
                .dto_type
                .clone()
                .or_else(|| {
                    entry.params.first().and_then(|p| match &p.ty {
                        IrTypeRef::Named(name) => Some(name.clone()),
                        _ => None,
                    })
                })
                .ok_or_else(|| {
                    crate::error::GenError::Parse(format!(
                        "clientAwait {} missing dto type",
                        entry.id
                    ))
                })?;
            let doc = entry
                .params
                .first()
                .map(|p| p.doc.clone())
                .unwrap_or_default();
            let _ = doc;
            Ok(vec![RustParam {
                name: "params".into(),
                ty: dto,
            }])
        }
        IrSerializeKind::ClientSplit => {
            let mut params = Vec::new();
            for param in &entry.params {
                let name = param.names.rust.clone();
                let ty = match &param.ty {
                    IrTypeRef::String => "&str".into(),
                    IrTypeRef::Named(dto) if !param.required => format!("Option<{dto}>"),
                    IrTypeRef::Named(dto) => dto.clone(),
                    other => {
                        return Err(crate::error::GenError::Parse(format!(
                            "unsupported split param type for {}: {other:?}",
                            entry.id
                        )));
                    }
                };
                params.push(RustParam { name, ty });
            }
            Ok(params)
        }
        other => Err(crate::error::GenError::Parse(format!(
            "unexpected serialize kind for {}: {other:?}",
            entry.id
        ))),
    }
}

fn rust_ok_type(entry: &IrEntryPoint) -> String {
    match entry.response.as_deref() {
        None | Some("void") => "()".into(),
        Some(_) if VALUE_OK_OPS.contains(&entry.id.as_str()) => "Value".into(),
        Some(name) => transport_ok_type(&entry.id, name).into(),
    }
}

/// Ops whose transport layer returns `serde_json::Value` despite a typed catalog response.
const VALUE_OK_OPS: &[&str] = &[
    "attachBusinessDetails",
    "bootstrapMcpProduct",
    "cancelPurchase",
    "checkLimits",
    "configureMcpPlans",
    "createPlan",
    "createProduct",
    "disableAutoRecharge",
    "getAutoRecharge",
    "getPaymentMethod",
    "getProduct",
    "listPlans",
    "listProducts",
    "reactivatePurchase",
    "saveAutoRecharge",
    "trackUsage",
    "trackUsageBulk",
    "updatePlan",
    "updateProduct",
];

fn transport_ok_type(id: &str, catalog_name: &str) -> &'static str {
    match id {
        "activatePlan" => "ActivatePlanResponseDto",
        "assignCredits" => "GrantCustomerCreditsResponse",
        "cloneProduct" => "CloneProductResult",
        "createCheckoutSession" => "CreateCheckoutSessionResponse",
        "createCustomer" => "CreateCustomerResult",
        "createCustomerSession" => "CreateCustomerSessionResponse",
        "createPaymentIntent" => "CreatePaymentIntentResult",
        "createTopupPaymentIntent" => "CreateTopupPaymentIntentResult",
        "getCustomer" => "CustomerResponseMapped",
        "getCustomerBalance" => "GetCustomerBalanceResult",
        "getMerchant" => "SdkMerchantResponseDto",
        "getPlatformConfig" => "SdkPlatformConfigResponseDto",
        "getUserInfo" => "UserInfoResponse",
        "processPaymentIntent" => "solvapay_dto::schemas::ProcessPaymentResult",
        "updateCustomer" => "UpdateCustomerResult",
        _ => match catalog_name {
            "void" => "()",
            _ => "Value",
        },
    }
}

fn serialize_kind(binding: &IrBindingSymbol) -> GenResult<IrSerializeKind> {
    match &binding.call {
        crate::ir::IrBindingCall::Wrap { serialize, .. } => Ok(*serialize),
        crate::ir::IrBindingCall::Verbatim => Err(crate::error::GenError::Parse(format!(
            "client binding {} is verbatim; expected wrap serialize",
            binding.id
        ))),
    }
}

fn format_params(params: &[RustParam]) -> String {
    if params.is_empty() {
        return String::new();
    }
    let parts = params
        .iter()
        .map(|p| format!(", {}: {}", p.name, p.ty))
        .collect::<Vec<_>>();
    parts.join("")
}

fn format_call_args(params: &[RustParam]) -> String {
    params
        .iter()
        .map(|p| p.name.as_str())
        .collect::<Vec<_>>()
        .join(", ")
}

fn binding_by_catalog(ir: &Ir, artifact: IrBindingArtifact) -> BTreeMap<String, &IrBindingSymbol> {
    ir.binding_symbols
        .values()
        .filter(|binding| binding.artifact == artifact)
        .filter_map(|binding| match &binding.catalog {
            IrBindingCatalogLink::Operation(id) => Some((id.clone(), binding)),
            _ => None,
        })
        .collect()
}

#[cfg(test)]
#[allow(clippy::unwrap_used, clippy::expect_used, clippy::panic)]
mod tests {
    use super::*;
    use crate::ir::{
        IrAvailability, IrBindingArg, IrBindingCall, IrDefaults, IrDocModel, IrEnvelopeMode,
        IrErrorKind, IrLangNames, IrParam, IrRubyReceiver, IrRubyTarget,
    };
    use std::collections::BTreeMap;

    #[test]
    fn emits_generated_header_and_impl_client() {
        let ir = sample_ir();
        let emitted = emit_client_rs(&ir).unwrap();
        assert!(emitted
            .client_generated_rs
            .contains("@generated by dto-gen — do not edit"));
        assert!(emitted.client_generated_rs.contains("impl Client {"));
        assert!(emitted
            .client_generated_rs
            .contains("pub async fn check_limits"));
        assert!(emitted
            .client_generated_rs
            .contains("self.inner.api.check_limits(params).await"));
    }

    #[test]
    fn emits_rustdoc_from_shared_doc_model() {
        let ir = sample_ir();
        let emitted = emit_client_rs(&ir).unwrap();
        assert!(emitted.client_generated_rs.contains(
            "/// Check remaining usage/spend limits for a customer against a product's plan."
        ));
        assert!(emitted.client_generated_rs.contains("/// # Arguments"));
        assert!(emitted
            .client_generated_rs
            .contains("/// * `params` — Limits request including customer and product refs."));
        assert!(emitted.client_generated_rs.contains("/// # Returns"));
    }

    #[test]
    fn emits_blocking_twin_with_block_on() {
        let ir = sample_ir();
        let emitted = emit_client_rs(&ir).unwrap();
        assert!(emitted
            .blocking_generated_rs
            .contains("impl BlockingClient {"));
        assert!(emitted
            .blocking_generated_rs
            .contains("pub fn check_limits"));
        assert!(emitted
            .blocking_generated_rs
            .contains("runtime().block_on(self.inner.check_limits(params))"));
        assert!(emitted.blocking_generated_rs.contains("/// # Arguments"));
    }

    #[test]
    fn emits_path_ref_and_ignore_shapes() {
        let ir = sample_ir();
        let emitted = emit_client_rs(&ir).unwrap();
        assert!(emitted
            .client_generated_rs
            .contains("pub async fn get_merchant(&self)"));
        assert!(emitted
            .client_generated_rs
            .contains("pub async fn get_product(&self, product_ref: &str)"));
        assert!(emitted.client_generated_rs.contains(
            "pub async fn delete_plan(&self, product_ref: &str, plan_ref: &str) -> Result<(), SdkError>"
        ));
    }

    fn sample_ir() -> Ir {
        let mut entry_points = BTreeMap::new();
        let mut binding_symbols = BTreeMap::new();

        entry_points.insert(
            "checkLimits".into(),
            entry(
                "checkLimits",
                "check_limits",
                vec![param_named(
                    "params",
                    "params",
                    "CheckLimitsRequest",
                    true,
                    "Limits request including customer and product refs.",
                )],
                Some("CheckLimitsRequest"),
                Some("LimitResponseWithPlan"),
                "Check remaining usage/spend limits for a customer against a product's plan.",
                Some("Current remaining limits, optionally including plan details."),
            ),
        );
        binding_symbols.insert(
            "checkLimits".into(),
            binding(
                "checkLimits",
                "check_limits",
                IrSerializeKind::ClientAwait,
                Some("CheckLimitsRequest"),
                vec![],
                vec![],
            ),
        );

        entry_points.insert(
            "getMerchant".into(),
            entry(
                "getMerchant",
                "get_merchant",
                vec![],
                None,
                Some("SdkMerchantResponseDto"),
                "Fetch the authenticated merchant profile.",
                None,
            ),
        );
        binding_symbols.insert(
            "getMerchant".into(),
            binding(
                "getMerchant",
                "get_merchant",
                IrSerializeKind::ClientIgnore,
                None,
                vec![],
                vec![],
            ),
        );

        entry_points.insert(
            "getProduct".into(),
            entry(
                "getProduct",
                "get_product",
                vec![param_string(
                    "productRef",
                    "product_ref",
                    true,
                    "Product ref.",
                )],
                None,
                Some("SdkProductResponse"),
                "Get a product by reference.",
                None,
            ),
        );
        binding_symbols.insert(
            "getProduct".into(),
            binding(
                "getProduct",
                "get_product",
                IrSerializeKind::ClientSplit,
                None,
                vec!["productRef".into()],
                vec!["&refs[0]".into()],
            ),
        );

        entry_points.insert(
            "deletePlan".into(),
            entry(
                "deletePlan",
                "delete_plan",
                vec![
                    param_string("productRef", "product_ref", true, "Product ref."),
                    param_string("planRef", "plan_ref", true, "Plan ref."),
                ],
                None,
                Some("void"),
                "Delete a plan.",
                None,
            ),
        );
        binding_symbols.insert(
            "deletePlan".into(),
            binding(
                "deletePlan",
                "delete_plan",
                IrSerializeKind::ClientSplit,
                None,
                vec!["productRef".into(), "planRef".into()],
                vec!["&refs[0]".into(), "&refs[1]".into()],
            ),
        );

        Ir {
            types: BTreeMap::new(),
            overlay_helpers: BTreeMap::new(),
            overlays: BTreeMap::new(),
            routes: vec![],
            error_templates: crate::ir::IrErrorTemplates::default(),
            entry_points,
            binding_symbols,
        }
    }

    fn entry(
        id: &str,
        rust: &str,
        params: Vec<IrParam>,
        request: Option<&str>,
        response: Option<&str>,
        summary: &str,
        returns: Option<&str>,
    ) -> IrEntryPoint {
        IrEntryPoint {
            id: id.into(),
            section: IrEntrySection::Operation,
            names: names(rust),
            optional_on_client: false,
            params,
            type_params: vec![],
            request: request.map(str::to_owned),
            response: response.map(str::to_owned),
            availability: availability(),
            sync_ts: IrSyncKind::Async,
            ruby_target: IrRubyTarget {
                owner: "SolvaPay::Client".into(),
                name: rust.into(),
                receiver: IrRubyReceiver::ClientInstance,
                takes_block: false,
            },
            defaults: IrDefaults::default(),
            errors: vec![IrErrorKind::Api],
            docs: IrDocModel {
                summary: summary.into(),
                returns: returns.map(str::to_owned),
            },
        }
    }

    fn binding(
        id: &str,
        rust: &str,
        serialize: IrSerializeKind,
        dto_type: Option<&str>,
        split_path_refs: Vec<String>,
        client_call_args: Vec<String>,
    ) -> IrBindingSymbol {
        IrBindingSymbol {
            id: id.into(),
            core: format!("solvapay_transport::SolvaPayClient::{rust}"),
            names: names(rust),
            catalog: IrBindingCatalogLink::Operation(id.into()),
            args: Vec::<IrBindingArg>::new(),
            split_path_refs,
            return_shape: "value".into(),
            sync: IrSyncKind::Async,
            envelope: IrEnvelopeMode::Async,
            artifact: IrBindingArtifact::Client,
            emit_order: 0,
            section: None,
            doc: String::new(),
            doc_wasm: None,
            rust_fn_name: rust.into(),
            call: IrBindingCall::Wrap {
                serialize,
                args: vec![],
            },
            verbatim_body: None,
            verbatim_body_wasm: None,
            dto_type: dto_type.map(str::to_owned),
            core_call: Some(rust.into()),
            client_call_args,
        }
    }

    fn param_named(name: &str, rust: &str, ty: &str, required: bool, doc: &str) -> IrParam {
        IrParam {
            name: name.into(),
            names: names(rust),
            required,
            ty: IrTypeRef::Named(ty.into()),
            default_value: None,
            doc: doc.into(),
        }
    }

    fn param_string(name: &str, rust: &str, required: bool, doc: &str) -> IrParam {
        IrParam {
            name: name.into(),
            names: names(rust),
            required,
            ty: IrTypeRef::String,
            default_value: None,
            doc: doc.into(),
        }
    }

    fn names(value: &str) -> IrLangNames {
        IrLangNames {
            ts: value.into(),
            py: value.into(),
            rb: value.into(),
            go: value.into(),
            rust: value.into(),
        }
    }

    fn availability() -> IrAvailability {
        IrAvailability {
            ts: vec![IrSyncKind::Async],
            py: vec![IrSyncKind::Async, IrSyncKind::Sync],
            rb: vec![IrSyncKind::Sync],
            go: vec![IrSyncKind::Sync],
            rust: vec![IrSyncKind::Async, IrSyncKind::Sync],
        }
    }
}
